mapper.select:
SELECT id, name, description, rule_type, point_value_min, point_value_max, trigger_condition, status, created_at, updated_at, created_by, updated_by, deleted, version FROM point_rule WHERE deleted = 0
AND name LIKE CONCAT('%', #{name}, '%')
AND rule_type = #{ruleType}
AND status = #{status}
ORDER BY created_at DESC
